(function() {
        function appendLink(href,options = {}) {
            var link = document.createElement("link");
            link.rel = 'stylesheet';
            link.type = "text/css";
            link.href = href;
            if(options.className){
                link.className = options.className;
            }
            document.head.appendChild(link);
        };

        function appendScript(src,isDefer) {
            var jsScript = document.createElement('script')
            jsScript.src = src
            if(isDefer){
                jsScript.async = false;
            }
            document.body.appendChild(jsScript)
        };
        function appendByReact(src,isDefer){
            if(window.$$_react_16_import_successed_){
                appendScript(src,isDefer)
            }else{
                document.addEventListener('react-require-16',
                    function(){
