                    }
                )
            }
        }

        function appendJsScript(src, options = {}) {
            var scriptElem = document.createElement('script');
            scriptElem.src = src;
            if (options.onload) scriptElem.onload = options.onload;
            if (options.className) scriptElem.className = options.className;
                        if (options.defer) scriptElem.async = false;
            document.head.appendChild(scriptElem);
        }

        function appendCssText(text, options = {}) {
            var styleElem = document.createElement('style');
            styleElem.textContent = text;
            if (options.className) styleElem.className = options.className;
            (options.parent || document.head).appendChild(styleElem);
        }

        function getCookieSimple(key) {
            var cookies = document.cookie.split('; ');
            for (var i = 0; i < cookies.length; i++) {
              var cookie = cookies[i];
              var parts = cookie.split('=');
              if (parts[0].trim() === key) {
                return parts.slice(1).join('=');
              }
            }
            return '';
        }

