                    isGray = true;
                }

                                if(blockAliIds && blockAliIds.indexOf(aliId) > -1) {
                    isGray = false;
                }
            }

            console.debug('ma-menu::judgeIsGray', cookieAliId, isGray);
            return isGray
        }

